<template>
  <div v-if="isLoading" class="d-flex justify-content-center align-items-center" style="height: 60vh;">
    <div class="spinner-border text-secondary" role="status">
      <span class="visually-hidden">Loading...</span>
    </div>
  </div>
  <div v-else-if="isOffline" class="offline-message d-flex flex-column align-items-center justify-content-center"
    style="min-height: 60vh;">
    <img src="../assets/btnAngerPulse.png" style="width: 200px; opacity: 0.5;" class="mb-4">
    <label class="b-24-gray text-center mb-3" v-html="t('offline.title')"></label>
    <p class="r-16-gray px-4 text-center" v-html="t('offline.dashboard')"></p>
    <p class="r-14-gray px-4 text-center mt-3" style="opacity: 0.7;" v-html="t('offline.subtitle')"></p>
  </div>
  <div v-else>
    <div>
      <label class="b-24-black" v-html="t('activity.title')"></label>
      <br>
    </div>
    <div class="text-start px-4 pt-3">
      <p class="b-16-gray" v-html="t('activity.temporalidad')"></p>
      <select id="FilterTempo" class="form-control w-100 select-ap" v-model="selectedOption"
        @change="GetDatos(selectedOption)" v-html="t('activity.ultsem')">
      </select>
      <div class="numeralia d-flex py-3">
        <div class="num-circle">
          <div class="circle-black b-48-gray p-3">
            <label class="m-auto">{{ dashboardStats.countAudios }}</label>
          </div>
        </div>
        <div class="data-rec b-20-gray w-100">
          <label class="m-auto px-3 b-20-gray" v-html="t('activity.audio')"></label>
        </div>
      </div>
      <div class="numeralia d-flex py-3">
        <!-- Si hay horas -->
        <div v-if="dashboardStats.tiempoResumen.h > 0" class="num-circle">
          <div class="circle-black b-20-gray p-3">
            <label class="m-auto">
              {{ dashboardStats.tiempoResumen.h }}:{{ dashboardStats.tiempoResumen.m.toString().padStart(2, '0') }}:{{
                dashboardStats.tiempoResumen.s.toString().padStart(2, '0') }}h
            </label>
          </div>
        </div>

        <!-- Si no hay horas pero hay minutos -->
        <div v-else-if="dashboardStats.tiempoResumen.m > 0" class="num-circle">
          <div class="circle-black b-20-gray p-3">
            <label class="m-auto">
              {{ dashboardStats.tiempoResumen.m }}:{{ dashboardStats.tiempoResumen.s.toString().padStart(2, '0') }}m
            </label>
          </div>
        </div>

        <!-- Si solo hay segundos -->
        <div v-else class="num-circle">
          <div class="circle-black b-20-gray p-3">
            <label class="m-auto">
              {{ dashboardStats.tiempoResumen.s.toString().padStart(2, '0') }}s
            </label>
          </div>
        </div>

        <div class="data-rec b-20-gray w-100">
          <label class="m-auto px-3 b-20-gray" v-html="t('activity.horas')"></label>
        </div>
      </div>

    </div>
    <!--Gráfica de barras-->
    <div class="card p-4 mt-4 shadow-sm">
      <p class="b-16-gray pt-2 pb-1 text-start" v-html="t('activity.dias')"></p>
      <div class="d-flex align-items-center mb-3">
        <!-- Botón de regreso dinámico -->
        <button v-if="temporalidad < 3" @click="goBack" class="btn btn-sm btn-outline-secondary me-3">
          ← {{ t('activity.btnBack') }}
        </button>
      </div>
      <div style="height: 300px; width: 100%;">
        <Bar v-if="apiData.length > 0" :data="dashboardStats.chartData" :options="chartOptions" />
        <div v-else class="d-flex justify-content-center align-items-center h-100">
          <p class="text-muted">{{ t('common.noData') }}</p>
        </div>
      </div>
    </div>

    <!--Mapa de calor-->
    <div class="py-3 px-4">
      <p class="b-16-gray pt-2 pb-1 text-start" v-html="t('activity.momentos')">
      </p>
      <div>
        <table class="pila-table">
          <tbody>
            <tr v-for="rowIndex in maxRows" :key="rowIndex">
              <td v-for="header in tableHeaders" :key="header.name">
                <div v-if="tableColumns[header.name][maxRows - rowIndex]" class="bloque-celda-wrapper">
                  <div class="bloque-celda"
                    :style="{ backgroundColor: getMomentoColor(tableColumns[header.name][maxRows - rowIndex].Momento) }"
                    @click="toggleTooltip(tableColumns[header.name][maxRows - rowIndex], $event)">
                    {{ tableColumns[header.name][maxRows - rowIndex].Bloque }}

                  </div>
                </div>
              </td>
            </tr>
          </tbody>
          <tfoot style="font-size: 12px;">
            <tr>
              <th v-for="header in tableHeaders" :key="header.name">
                {{ header.name }}
              </th>
            </tr>
          </tfoot>
        </table>
      </div>
      <div class="d-flex justify-content-start pt-4">
        <div class="mini-square" style="background-color: #efefef; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.registro') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[0] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[0] || 0) }}
          </div>
        </div>
      </div>
      <div class="d-flex justify-content-start pt-4">
        <div class="mini-square" style="background-color: #E3FCFF; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.act') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[1] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[1] || 0) }}
          </div>
        </div>
      </div>
      <div class="d-flex justify-content-start pt-3">
        <div class="mini-square" style="background-color: #FFE4B3; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.mente') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[2] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[2] || 0) }}
          </div>
        </div>
      </div>
      <div class="d-flex justify-content-start pt-3">
        <div class="mini-square" style="background-color: #FFC4B3; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.lugares') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[3] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[3] || 0) }}
          </div>
        </div>
      </div>
      <div class="d-flex justify-content-start pt-3">
        <div class="mini-square" style="background-color: #FF9797; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.palabras') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[4] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[4] || 0) }}
          </div>
        </div>
      </div>
      <div class="d-flex justify-content-start pt-3 pb-4">
        <div class="mini-square" style="background-color: #fb5353; margin-top:2px;"></div>
        <div class="ps-3">
          <div class="b-14-gray text-start">
            {{ t('activity.hablar') }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.audio')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.audioMin') }}: {{ dashboardStats.resumenMomentos[5] || 0 }}
          </div>
          <div class="r-12-gray text-start" v-tooltip="t('activity.horas')"
            style="padding-right: 10px; width: fit-content; cursor: help;">
            {{ t('activity.horasMin') }}: {{ formatTiempo(dashboardStats.resumenTiempo?.[5] || 0) }}
          </div>
        </div>
      </div>
    </div>
    <Teleport to="body">
      <div v-if="selectedBlock" class="custom-tooltip" :style="tooltipStyle">
        <strong>{{ t('activity.audioMin') }}:</strong> {{ selectedBlock.Cantidad }}
        <br>
        <strong>{{ t('activity.horasMin') }}:</strong> {{ formatTiempo(selectedBlock.Tiempo) }}
        <div class="tooltip-arrow" :style="arrowStyle"></div>
      </div>
    </Teleport>
  </div>
</template>

<script setup>
/*Imports*/
import { ref, computed, onMounted, onUnmounted } from 'vue';
import { API_BASE_URL } from '@/config/api'
import { useI18n } from 'vue-i18n'
import { Tooltip } from 'bootstrap';
import { Bar } from 'vue-chartjs';
import { Chart as ChartJS, Title, Tooltip as ChartTooltip, Legend, BarElement, CategoryScale, LinearScale } from 'chart.js';
import ChartDataLabels from 'chartjs-plugin-datalabels';

// Registramos el plugin en ChartJS
ChartJS.register(Title, ChartTooltip, Legend, BarElement, CategoryScale, LinearScale, ChartDataLabels);

/*Declaraciones*/
const { t, locale } = useI18n();
const temporalidad = ref(1);
const selectedOption = ref(1)
const mesSeleccionado = ref(0);
const semanaSeleccionada = ref(0);
const diaSeleccionado = ref(0)
const isLoading = ref(true); // Estado de carga
//Map de calor
const apiData = ref([]);
const selectedBlock = ref(null); // Estado para controlar qué tooltip está abierto
// const dataColorEs = ref({});
const coloresMomentos = [
  "#efefef", // Momento 0
  "#E3FCFF", // Momento 1
  "#FFE4B3", // Momento 2
  "#FFC4B3", // Momento 3
  "#FF9797", // Momento 4
  "#fb5353"  // Momento 5
];

const isOffline = ref(!navigator.onLine);

onMounted(() => {
  GetMomentsAudios();
  window.addEventListener('click', handleGlobalClick);
  window.addEventListener('online', updateOnlineStatus);
  window.addEventListener('offline', updateOnlineStatus);
});

onUnmounted(() => {
  window.removeEventListener('click', handleGlobalClick); //Removemos la escucha del click global
  window.removeEventListener('online', updateOnlineStatus);
  window.removeEventListener('offline', updateOnlineStatus);
});

function updateOnlineStatus() {
  isOffline.value = !navigator.onLine;
  if (!isOffline.value && apiData.value.length === 0) {
    isLoading.value = true;
    GetMomentsAudios();
  }
}

function GetDatos(x) {
  temporalidad.value = x;
  selectedOption.value = x;
  GetMomentsAudios();
}

/* Apis */
//Momentos
async function GetMomentsAudios() {
  if (isOffline.value) {
    isLoading.value = false;
    return;
  }
  try {
    const sesion = localStorage.getItem("token");
    if (!sesion) return;

    const response = await fetch(`${API_BASE_URL}/api/config/GetUserMoments`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        user: sesion, temporalidad: temporalidad.value, mes: mesSeleccionado.value,
        semana: semanaSeleccionada.value, dia: diaSeleccionado.value
      })
    })

    const data = await response.json()
    const parsedData = typeof data.data === 'string' ? JSON.parse(data.data) : data.data;

    apiData.value = Array.isArray(parsedData) ? parsedData : [];

    console.log(apiData.value)
  }
  catch (e) {
    console.error("Error momentos", e)
  } finally {
    isLoading.value = false;
  }
}

/* Funciones generales */
// Función para manejar el clic global y cerrar tooltips
const handleGlobalClick = (event) => {
  if (!event.target.closest('.bloque-celda') && !event.target.closest('.custom-tooltip')) {
    selectedBlock.value = null;
  }
};
const formatTiempo = (segundos) => {
  if (segundos === 0 || !segundos) return "0s";

  if (segundos < 60) {
    // Menos de un minuto
    return `${segundos}s`;
  } else if (segundos < 3600) {
    // Menos de una hora -> Convertir a minutos
    const minutos = Math.floor(segundos / 60);
    const segundosRestantes = segundos % 60;

    // Si los segundos restantes son 0, solo mostramos minutos
    return segundosRestantes === 0
      ? `${minutos}m`
      : `${minutos}m ${segundosRestantes}s`;
  } else {
    // Una hora o más
    const horas = Math.floor(segundos / 3600);
    const minutosRestantes = Math.floor((segundos % 3600) / 60);

    return minutosRestantes === 0
      ? `${horas}h`
      : `${horas}h ${minutosRestantes}m`;
  }
};

/* Estadísticas Combinadas O(N) */
const dashboardStats = computed(() => {
  let countAudios = 0;
  let totalSegundos = 0;

  const grupos = new Map();
  const resumenMomentos = {};
  const resumenTiempo = {};

  if (!apiData.value || apiData.value.length === 0) {
    return {
      countAudios: 0,
      tiempoResumen: { h: 0, m: 0, s: 0 },
      chartData: { labels: [], rawItems: [], datasets: [] },
      resumenMomentos: {},
      resumenTiempo: {}
    };
  }

  // Iteración ÚNICA sobre todo el arreglo data
  apiData.value.forEach(item => {
    const cantidad = item.Cantidad || 0;
    const tiempo = item.Tiempo || 0;
    const momento = item.Momento;

    // 1. Conteo total de audios y segundos
    countAudios += cantidad;
    totalSegundos += tiempo;

    // 2. Gráfica de barras
    const n = item.Numero;
    if (!grupos.has(n)) {
      grupos.set(n, {
        label: locale.value.startsWith('es') ? item.Etiqueta : item.Label,
        cantidad: 0,
        numero: n
      });
    }
    grupos.get(n).cantidad += cantidad;

    // 3. Resúmenes de Momentos
    if (momento !== undefined && momento !== null) {
      if (!resumenMomentos[momento]) resumenMomentos[momento] = 0;
      if (!resumenTiempo[momento]) resumenTiempo[momento] = 0;

      resumenMomentos[momento] += cantidad;
      resumenTiempo[momento] += tiempo;
    }
  });

  const datosEnOrden = Array.from(grupos.values());

  return {
    countAudios,
    tiempoResumen: {
      h: Math.floor(totalSegundos / 3600),
      m: Math.floor((totalSegundos % 3600) / 60),
      s: totalSegundos % 60
    },
    chartData: {
      labels: datosEnOrden.map(d => d.label),
      rawItems: datosEnOrden,
      datasets: [
        {
          label: t('activity.cantidadAudios'),
          data: datosEnOrden.map(d => d.cantidad),
          backgroundColor: '#177e99',
          borderRadius: 4,
          barThickness: 25
        }
      ]
    },
    resumenMomentos,
    resumenTiempo
  };
});


//Configuración de gráfica
const chartOptions = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { display: false },
    tooltip: {
      enabled: false
    },
    datalabels: {
      anchor: 'end',
      align: 'top',
      formatter: Math.round,
      font: {
        weight: 'bold',
        size: 12
      },
      color: '#333'
    }
  },
  layout: {
    padding: {
      top: 20
    }
  },
  scales: {
    y: {
      beginAtZero: true,
      grid: { display: false },
      ticks: { display: false }
    },
    x: {
      grid: { display: false }
    }
  },
  onClick: (event, elements) => {
    if (elements.length > 0) {
      const index = elements[0].index;
      const selectedItem = dashboardStats.value.chartData.rawItems[index];

      handleDrillDown(selectedItem.numero);
    }
  },
  // Importante para que el cursor cambie al pasar sobre las barras
  onHover: (event, chartElement) => {
    event.native.target.style.cursor = chartElement[0] ? 'pointer' : 'default';
  }
};
//Bajar de nivel
const handleDrillDown = (numero) => {
  if (temporalidad.value == 3) {
    mesSeleccionado.value = numero;
    temporalidad.value = 2;
  }
  else if (temporalidad.value == 2) {
    semanaSeleccionada.value = numero;
    temporalidad.value = 1;
  }
  else if (temporalidad.value == 1) {
    diaSeleccionado.value = numero;
    temporalidad.value = 1;
  }
  // Refrescamos los datos con los nuevos filtros
  selectedOption.value = temporalidad.value;
  GetMomentsAudios();
};
//Regresar
const goBack = () => {
  if (temporalidad.value == 1 && diaSeleccionado.value == 0) {
    temporalidad.value = 2;
    semanaSeleccionada.value = 0;
    diaSeleccionado.value = 0;
  } else if (temporalidad.value == 1 && diaSeleccionado.value > 0) {
    temporalidad.value = 1;
    diaSeleccionado.value = 0;
  } else if (temporalidad.value == 2) {
    temporalidad.value = 3;
    mesSeleccionado.value = 0;
  }
  selectedOption.value = temporalidad.value;
  GetMomentsAudios();
};

/* Funciones de Mapa de calor */
//Nombre de columnas
// const tableHeaders = computed(() => {
//   if (!apiData.value.length) return [];

//   const allLabels = apiData.value.map(item => ({
//     name: locale.value.startsWith('es') ? item.Etiqueta : item.Label,
//     numero: item.Numero
//   }));

//   const uniqueHeaders = allLabels.filter((value, index, self) =>
//     index === self.findIndex((t) => t.name === value.name)
//   );

//   return uniqueHeaders.sort((a, b) => a.numero - b.numero);
// });
const tableHeaders = computed(() => {
  if (!apiData.value.length) return [];

  // 1. Extraemos los nombres en el orden exacto en que vienen del back
  const allLabels = apiData.value.map(item => ({
    name: locale.value.startsWith('es') ? item.Etiqueta : item.Label,
    numero: item.Numero
  }));

  // 2. Filtramos duplicados PERO mantenemos el orden de aparición original
  const uniqueHeaders = allLabels.filter((value, index, self) =>
    index === self.findIndex((t) => t.name === value.name)
  );

  // 3. RETORNAMOS sin el .sort()
  return uniqueHeaders;
});


//Obtener color del momento
const getMomentoColor = (momento) => {
  return coloresMomentos[momento] || "#FFFFFF";
};
//Datos de Mapa
const tableColumns = computed(() => {
  if (!apiData.value.length || !tableHeaders.value.length) return {};
  console.log(apiData.value)
  const columns = {};

  tableHeaders.value.forEach(header => {
    const registrosDia = apiData.value.filter(item => {
      const itemName = locale.value.startsWith('es') ? item.Etiqueta : item.Label;
      return itemName === header.name && item.Bloque;
    });

    columns[header.name] = registrosDia.sort((a, b) => a.Bloque.localeCompare(b.Bloque));
  });
  console.log(columns)
  return columns;
});




// Calculamos el número máximo de filas para que la tabla sea uniforme
const maxRows = computed(() => {
  const counts = Object.values(tableColumns.value).map(col => col.length);
  return counts.length ? Math.max(...counts) : 0;
});
const tooltipStyle = ref({});
const arrowStyle = ref({});

// Función para alternar el tooltip (abrir/cerrar al hacer click)
const toggleTooltip = (block, event) => {
  if (selectedBlock.value === block) {
    selectedBlock.value = null;
  } else {
    selectedBlock.value = block;
    if (event && event.currentTarget) {
      const rect = event.currentTarget.getBoundingClientRect();
      const scrollY = window.scrollY || window.pageYOffset;
      const scrollX = window.scrollX || window.pageXOffset;

      const top = rect.top + scrollY - 45; // 45px arriba de la celda
      let left = rect.left + scrollX + (rect.width / 2);

      // Umbral para determinar colisiones ajustado a 70px
      if (left < 70) {
        tooltipStyle.value = { position: 'absolute', top: `${top}px`, left: '10px', transform: 'none', zIndex: 9999 };
        arrowStyle.value = { left: `${left - 10}px`, right: 'auto', marginLeft: '-5px' };
      } else if (window.innerWidth - left < 70) {
        tooltipStyle.value = { position: 'absolute', top: `${top}px`, right: '10px', left: 'auto', transform: 'none', zIndex: 9999 };
        const arrowRight = window.innerWidth - left - 10;
        arrowStyle.value = { left: 'auto', right: `${arrowRight}px`, marginLeft: '0px' };
      } else {
        tooltipStyle.value = { position: 'absolute', top: `${top}px`, left: `${left}px`, transform: 'translateX(-50%)', zIndex: 9999 };
        arrowStyle.value = { left: '50%', right: 'auto', marginLeft: '-5px' };
      }
    }
  }
};
// Resúmenes han sido movidos a dashboardStats (O(N) unificado).

//Tooltips de momentos
const vTooltip = {
  mounted(el, binding) {
    el._tooltip = new Tooltip(el, {
      title: binding.value,
      placement: 'top',
      trigger: 'hover'
    });
  },
  updated(el, binding) {
    if (el._tooltip && binding.value !== binding.oldValue) {
      el._tooltip.setContent({ '.tooltip-inner': binding.value });
    }
  },
  unmounted(el) {
    if (el._tooltip) {
      el._tooltip.dispose();
      delete el._tooltip;
    }
  }
};
</script>
<style scoped>
.pila-table {
  width: 100%;
  border-collapse: collapse;
}

.pila-table td {
  vertical-align: bottom;
  height: 50px;
  border: 1px solid #eee;
  padding: 0px;
}

.bloque-celda {
  background-color: #f0f4f8;
  border-radius: 4px;
  padding: 8px;
  margin: 2px 0;
  text-align: center;
  font-weight: bold;
}

.pila-table th {
  padding: 12px;
  background-color: #2c3e50;
  color: white;
}

.bloque-celda {
  border-radius: 4px;
